WITH Union_CTE as /* Merge together comm records and ubc status start records. Only include the first UBC record (ubc_order = 1). A new window will start with the first UBC status.*/ ( SELECT d.case_id ,comm_time_objid ,null as ubc_status_id ,cast(dateadd(minute, datediff(minute, 0, note_creation_time), 0) AS SMALLDATETIME) as note_creation_time ,default_sla_duration_secs ,next_update_duration_secs ,next_update ,case when next_update in ('None Currently Planned','Awaiting Customer Reply','Ticket set to Auto Close','Ticket Closed') then null --convert(datetime, '2079-06-06', 120) else convert(datetime, convert(nchar(16), next_update, 120), 120) end as next_update_time FROM dbo.case_variable_comm_detail d INNER JOIN dbo.TSC_METRIC_MAIN c ON c.case_id = d.case_id AND c.case_type='Customer Trouble' AND c.case_open_dt >= '2016/07/17' AND c.case_close_dt >= '1/1/1900'
)
SELECT case_id , comm_time_objid , ubc_status_id , note_creation_time , default_sla_duration_secs , next_update_duration_secs , next_update , case when DATEDIFF(minute, note_creation_time, next_update_time) < 1 then null else next_update_time end as next_update_time , case when next_update_time is null then 'System Pause' when DATEDIFF(minute, note_creation_time, next_update_time) < 1 then 'Data Quality Pause' else 'Not a Pause' end as pause_type , ROW_NUMBER() OVER(PARTITION BY case_id ORDER BY note_creation_time, comm_time_objid) as case_comm_order , DATEADD(dd, 0, DATEDIFF(dd, 0, GETDATE())) as bira_load_date FROM Union_CTE

SQLTask:SqlTaskData.SQLTask:SqlStatementSource:
DECLARE @JobID VARCHAR(4000) = ?; 

DECLARE @JobName  VARCHAR(100); 

DECLARE @SQLStatement NVARCHAR(500); 


IF (LEFT(@JobID,2) = '0x') -- start of the binary representation, so we have a job GUID 

       BEGIN 


  SELECT @SQLStatement =  

  ' 

   SELECT @JobNameOUT = [Name] 

   FROM msdb.dbo.sysjobs   

   WHERE job_id = CONVERT(UNIQUEIDENTIFIER,' +  @JobID + ');  

  ' 

  EXEC sp_executesql @SQLStatement, N'@JobNameOUT VARCHAR(100) OUTPUT', @JobNameOUT = @JobName OUTPUT; 


  Select @JobName as Job_Name; 

       END 

ELSE 

       BEGIN 

   Select 'The package was started manually.' as Job_Name; 

END
